describe("mergePullRequest", () => {
	const baseMerge = {
		owner: "o",
		repo: "r",
		number: 7,
		token: "ghp_x",
	};

	test("returns merged on 200 with merged=true", async () => {
		const { fetch, calls } = recordingFetch([jsonResponse(200, { merged: true, sha: "abc123" })]);
		const result = await mergePullRequest({ ...baseMerge, fetch });
		expect(result.kind).toBe("merged");
		expect((result as { sha: string }).sha).toBe("abc123");
		expect(calls[0]?.method).toBe("PUT");
		expect(calls[0]?.url).toBe("https://api.github.com/repos/o/r/pulls/7/merge");
		expect(calls[0]?.headers.authorization).toBe("Bearer ghp_x");
		expect(JSON.parse(calls[0]?.body ?? "{}")).toEqual({ merge_method: "merge" });
	});

	test("forwards merge_method and commit_message", async () => {
		const { fetch, calls } = recordingFetch([jsonResponse(200, { merged: true, sha: "def" })]);
		await mergePullRequest({
			...baseMerge,
			mergeMethod: "squash",
			commitMessage: "chore: merge",
			fetch,
		});
		expect(JSON.parse(calls[0]?.body ?? "{}")).toEqual({
			merge_method: "squash",
			commit_message: "chore: merge",
		});
	});

	test("detects already_merged via 405 body", async () => {
		const { fetch } = recordingFetch([
			jsonResponse(405, { message: "Pull Request is already merged" }),
		]);
		const result = await mergePullRequest({ ...baseMerge, fetch });
		expect(result.kind).toBe("already_merged");
	});

	test("returns not_mergeable on 405 with non-merged message", async () => {
		const { fetch } = recordingFetch([
			jsonResponse(405, { message: "Pull Request is not mergeable" }),
		]);
		const result = await mergePullRequest({ ...baseMerge, fetch });
		expect(result.kind).toBe("not_mergeable");
		expect((result as { message: string }).message).toContain("not mergeable");
	});

	test("returns rate_limited on 403 with x-ratelimit-remaining=0", async () => {
		const resetEpoch = 1_700_000_000;
		const response = new Response(JSON.stringify({ message: "rate limit exceeded" }), {
			status: 403,
			headers: {
				"content-type": "application/json",
				"x-ratelimit-remaining": "0",
				"x-ratelimit-reset": String(resetEpoch),
			},
		});
		const { fetch } = recordingFetch([response]);
		const result = await mergePullRequest({ ...baseMerge, fetch });
		expect(result.kind).toBe("rate_limited");
		expect((result as { resetAt: string | null }).resetAt).toBe(
			new Date(resetEpoch * 1000).toISOString(),
		);
	});

	test("returns rate_limited on 429", async () => {
		const { fetch } = recordingFetch([jsonResponse(429, { message: "slow down" })]);
		const result = await mergePullRequest({ ...baseMerge, fetch });
		expect(result.kind).toBe("rate_limited");
	});

	test("returns not_found on 404", async () => {
		const { fetch } = recordingFetch([jsonResponse(404, { message: "Not Found" })]);
		const result = await mergePullRequest({ ...baseMerge, fetch });
		expect(result.kind).toBe("not_found");
	});

	test("missing token short-circuits", async () => {
		const result = await mergePullRequest({ ...baseMerge, token: "" });
		expect(result.kind).toBe("missing_token");
	});

	test("network failure surfaces", async () => {
		const failing = (async () => {
			throw new Error("ECONNREFUSED");
		}) as unknown as typeof fetch;
		const result = await mergePullRequest({ ...baseMerge, fetch: failing });
		expect(result.kind).toBe("network");
		expect((result as { message: string }).message).toContain("ECONNREFUSED");
	});
});

import { afterEach, beforeEach, describe, expect, test } from "bun:test";
import type { OpenPullRequestInput, OpenPullRequestResult } from "../pr.ts";
import { reapRun } from "./index.ts";
import {
	type Ctx,
	fakeBurrowClient,
	fakeExec,
	fakeFs,
	makeBurrow,
	makePool,
	setup,
} from "./test-helpers.ts";

describe("reapRun pr_open sub-step (warren-f6af)", () => {
	let ctx: Ctx;

	beforeEach(async () => {
		ctx = await setup();
	});

	afterEach(async () => {
		await ctx.db.close();
	});

	function fakeOpenPr(
		responses: ReadonlyArray<OpenPullRequestResult | (() => OpenPullRequestResult)>,
	): {
		openPr: (input: OpenPullRequestInput) => Promise<OpenPullRequestResult>;
		calls: OpenPullRequestInput[];
	} {
		const calls: OpenPullRequestInput[] = [];
		let i = 0;
		const openPr = async (input: OpenPullRequestInput): Promise<OpenPullRequestResult> => {
			calls.push(input);
			const r = responses[i++];
			if (r === undefined) throw new Error("fakeOpenPr: out of responses");
			return typeof r === "function" ? r() : r;
		};
		return { openPr, calls };
	}

	test("opens PR after a successful push with real commits and persists prUrl", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([{ ok: true, url: "https://github.com/x/y/pull/77", mode: "created" }]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			broker: ctx.broker,
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBe("https://github.com/x/y/pull/77");
		expect(pr.calls).toHaveLength(1);
		expect(pr.calls[0]?.owner).toBe("x");
		expect(pr.calls[0]?.repo).toBe("y");
		expect(pr.calls[0]?.head).toBe("agent/refactor-bot/run-1");
		expect(pr.calls[0]?.base).toBe("main");
		expect((await ctx.repos.runs.require(ctx.runId)).prUrl).toBe("https://github.com/x/y/pull/77");
		const events = await ctx.repos.events.listByRun(ctx.runId);
		const opened = events.find((ev) => ev.kind === "reap.pr_opened");
		expect(opened?.payloadJson).toMatchObject({
			prUrl: "https://github.com/x/y/pull/77",
			mode: "created",
		});
		const completed = events.find((ev) => ev.kind === "reap.completed");
		expect(completed?.payloadJson).toMatchObject({ prUrl: "https://github.com/x/y/pull/77" });
	});

	test("skips pr_open when autoOpenPr is omitted (default off in tests)", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBeNull();
		expect(pr.calls).toHaveLength(0);
		const events = await ctx.repos.events.listByRun(ctx.runId);
		expect(events.find((ev) => ev.kind === "reap.pr_opened")).toBeUndefined();
	});

	test("skips pr_open when autoOpenPr is disabled", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: false, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBeNull();
		expect(pr.calls).toHaveLength(0);
	});

	test("skips pr_open when outcome is failed (conservative V1)", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "failed",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBeNull();
		expect(pr.calls).toHaveLength(0);
	});

	test("skips pr_open when push lands no commits (commitsAhead === 0)", async () => {
		const e = fakeExec({ revListCount: "0" });
		const pr = fakeOpenPr([]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBeNull();
		expect(pr.calls).toHaveLength(0);
	});

	test("skips pr_open when branch matches project.defaultBranch", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow({ branch: "main" })), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBeNull();
		expect(pr.calls).toHaveLength(0);
	});

	test("skips pr_open when push failed", async () => {
		const e = fakeExec({ fail: "remote rejected" });
		const pr = fakeOpenPr([]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.branchPushed).toBe(false);
		expect(result.prUrl).toBeNull();
		expect(pr.calls).toHaveLength(0);
	});

	test("emits reap_failed step=pr_open when token is missing but auto-open enabled", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBeNull();
		expect(result.errors.map((x) => x.step)).toContain("pr_open");
		expect(pr.calls).toHaveLength(0);
		const events = await ctx.repos.events.listByRun(ctx.runId);
		const failed = events.find(
			(ev) =>
				ev.kind === "reap_failed" &&
				typeof ev.payloadJson === "object" &&
				ev.payloadJson !== null &&
				(ev.payloadJson as { step?: string }).step === "pr_open",
		);
		expect(failed).toBeDefined();
	});

	test("treats 'pr already exists' (mode=exists) as success and persists the existing url", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([{ ok: true, url: "https://github.com/x/y/pull/3", mode: "exists" }]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBe("https://github.com/x/y/pull/3");
		expect(result.errors.map((x) => x.step)).not.toContain("pr_open");
		expect((await ctx.repos.runs.require(ctx.runId)).prUrl).toBe("https://github.com/x/y/pull/3");
	});

	test("emits reap_failed step=pr_open when openPr returns network error", async () => {
		const e = fakeExec({ revListCount: "2" });
		const pr = fakeOpenPr([{ ok: false, reason: "network", message: "ECONNREFUSED" }]);
		const result = await reapRun({
			runId: ctx.runId,
			outcome: "succeeded",
			repos: ctx.repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), ctx.repos),
			fs: fakeFs().fs,
			exec: e.exec,
			autoOpenPr: { enabled: true, token: "ghp_xyz", warrenBaseUrl: null },
			openPr: pr.openPr,
		});
		expect(result.prUrl).toBeNull();
		expect(result.errors.map((x) => x.step)).toContain("pr_open");
		expect(result.state).toBe("succeeded");
	});
});

